import { d3_map } from "../../../core/d3-constants";
import { Registry  } from "../../../core/zc-registry";

export function getGroupByColumnData(spec){
    let { column, data } = spec;

    if(!data){
        data = this.data[0].data[0]; //3d array data
    }
    let columnInfo = this.getColumnByColumnName(column),
        { dataindex } =  columnInfo

    return nest(data, dataindex);
}

function nest(data, index){
    let groups = d3_map();
    
        
    data.map(d => {
        if(groups.has(d[index])){
            let group = groups.get(d[index]);
            group.push(d);

        }else{
            groups.set(d[index], [d]);
        }
    })
    return reGroupAsArray(groups);
    
}

function reGroupAsArray(groups){
    let keys = groups.keys(),
        arrayGroup = new Array(0);
    keys.map(d => {
        let group = groups.get(d);
        arrayGroup.push({
            'seriesname': d,
            'data': group
        })
    })
    return arrayGroup;
}

Registry.setComponent("column_groupBy", getGroupByColumnData);